const projectId = $('Receive Project').first().json.project_id;
const project = $('Load Project').first().json;
const design = $('Load Selected Design Option').first().json;
const briefing = $('Load Briefing').first().json;
const agentPrompt = $('Load Agent Prompt').first().json;

let designContent = {};
try { designContent = typeof design.content === 'string' ? JSON.parse(design.content) : (design.content || {}); } catch(e) {}

let briefingContent = {};
try { briefingContent = typeof briefing.content === 'string' ? JSON.parse(briefing.content) : (briefing.content || {}); } catch(e) {}

const designStr = JSON.stringify(designContent).toLowerCase();
const briefStr = JSON.stringify(briefingContent).toLowerCase();
const hasStructural = designStr.includes('estructur') || briefStr.includes('estructur') || designStr.includes('structural');

const roomsAffected = briefingContent.rooms_affected || [];
const constraints = briefingContent.constraints || [];

const designSummary = design.title
  ? `Opción ${design.option_number}: ${design.title}\n${design.description || ''}`
  : JSON.stringify(designContent, null, 2);

const roomsText = roomsAffected.length > 0
  ? roomsAffected.map(r => `- ${r.room}: ${r.intervention}`).join('\n')
  : '- Sin detalle disponible';

const constraintsText = constraints.length > 0
  ? constraints.map(c => `- ${c.description}`).join('\n')
  : '- Sin restricciones específicas';

const outputFormat = '{\n  "regulatory_tasks": [\n    {\n      "task_type": "licencia_obra|comunicacion_previa|permiso_comunidad|certificado_habitabilidad|cedula_urbanistica|informe_tecnico|otro",\n      "title": "string",\n      "description": "string",\n      "entity": "string",\n      "required_docs": ["string"],\n      "estimated_timeline": "string",\n      "estimated_cost": null,\n      "priority": "critico|importante|recomendable|informativo",\n      "draft_message": "string",\n      "notes": "string"\n    }\n  ]\n}';

const userPrompt = `Detecta trámites y permisos potencialmente necesarios para este proyecto.\n\nPROYECTO:\n- Tipo de intervención: ${project.project_type || 'reforma'}\n- Localización: ${project.location_city || ''}, ${project.location_province || ''}\n- Tipo de inmueble: ${project.property_type || ''}\n- Superficie: ${project.property_area_m2 || ''} m²\n\nPROPUESTA DE DISTRIBUCIÓN SELECCIONADA:\n${designSummary}\n\nINTERVENCIONES PREVISTAS:\n${roomsText}\n\nRESTRICCIONES CONOCIDAS:\n${constraintsText}\n\n¿HAY AFECTACIÓN ESTRUCTURAL PREVISTA?: ${hasStructural ? 'Posiblemente sí' : 'No indicado explícitamente'}\n\nResponde EXCLUSIVAMENTE con un objeto JSON válido:\n${outputFormat}`;

return [{ json: {
  project_id: projectId,
  prompt_system: agentPrompt.content || 'Eres el Agente de Normativa y Tramitación.',
  prompt_user: userPrompt,
  model: agentPrompt.model_recommended || 'claude-sonnet-4-20250514',
  temperature: agentPrompt.temperature || 0.2
}}];

const llmResponse = $input.first().json;
const projectId = $('Receive Project').first().json.project_id;

let content = llmResponse.content || llmResponse.response || llmResponse.text || '';
if (typeof content === 'object') content = JSON.stringify(content);
content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed = {};
try {
  parsed = JSON.parse(content);
} catch(e) {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) { try { parsed = JSON.parse(match[0]); } catch(e2) {} }
}

const tasks = parsed.regulatory_tasks || [];

if (tasks.length === 0) {
  return [{ json: {
    project_id: projectId,
    task_type: 'otro',
    title: 'Análisis normativo preliminar',
    description: 'No se detectaron trámites específicos. Verificar manualmente con técnico.',
    entity: 'Ayuntamiento local',
    required_docs: '[]',
    estimated_timeline: 'Por determinar',
    estimated_cost: null,
    priority: 'informativo',
    draft_message: '',
    notes: 'El LLM no devolvió trámites específicos.'
  }}];
}

return tasks.map(task => ({ json: {
  project_id: projectId,
  task_type: task.task_type || 'otro',
  title: task.title || 'Trámite sin título',
  description: task.description || '',
  entity: task.entity || '',
  required_docs: JSON.stringify(task.required_docs || []),
  estimated_timeline: task.estimated_timeline || '',
  estimated_cost: task.estimated_cost || null,
  priority: task.priority || 'informativo',
  draft_message: task.draft_message || '',
  notes: task.notes || ''
}}));

const approval = $('Create Approval').first().json;
const data = $('Collect All Tasks').first().json;
const resumeUrl = $execution.resumeUrl;

const approveUrl = resumeUrl + '?action=approve';
const rejectUrl = resumeUrl + '?action=reject';

const htmlBody = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;"><h2 style="color:#2c3e50;">Studio AI — Revisión normativa</h2><p>El análisis normativo ha detectado <strong>${data.critical_count} trámite(s) crítico(s)</strong> que pueden requerir consulta con organismos oficiales.</p><h3 style="color:#e67e22;">Trámites detectados:</h3><pre style="background:#f8f9fa;padding:16px;border-radius:4px;font-size:13px;white-space:pre-wrap;">${data.tasks_summary}</pre><p><strong>¿Autoriza preparar el contacto con los organismos correspondientes?</strong><br><em>Los borradores de comunicación están listos. El envío real requerirá su aprobación final.</em></p><div style="margin:30px 0;"><a href="${approveUrl}" style="background-color:#27ae60;color:white;padding:12px 24px;text-decoration:none;border-radius:4px;margin-right:16px;">✅ Autorizar contacto</a>&nbsp;&nbsp;<a href="${rejectUrl}" style="background-color:#95a5a6;color:white;padding:12px 24px;text-decoration:none;border-radius:4px;">⏸️ No por ahora</a></div><p style="color:#95a5a6;font-size:12px;">Este enlace expira en 72 horas.</p></div>`;

return [{ json: {
  html_body: htmlBody,
  subject: `[Studio AI] Revisión normativa — ${data.critical_count} trámite(s) crítico(s)`,
  to: 'arquitecto@estudio.com',
  project_id: data.project_id,
  tasks_count: data.tasks_count,
  critical_count: data.critical_count,
  approval_id: approval.id
}}];
